from __future__ import annotations

from dataclasses import dataclass
import json
import logging
from typing import Literal
from urllib.parse import urlparse

from server.config import BaseConfig, get_app_config
from server.utils.logging import get_app_logger

StartupAppRole = Literal["main_app", "game_server"]

_MIN_SECRET_BYTES = 32
_LOCAL_HOSTS = {"localhost", "127.0.0.1", "::1", "0.0.0.0"}
_PLACEHOLDER_SECRET_MARKERS = (
    "changeme",
    "change-me",
    "change_me",
    "development",
    "dev-secret",
    "example",
    "placeholder",
    "test-secret",
)


@dataclass(frozen=True)
class StartupAlert:
    code: str
    message: str


def _is_production(cfg: BaseConfig) -> bool:
    return not bool(getattr(cfg, "IS_DEV", False) or getattr(cfg, "TESTING", False))


def _has_min_secret(value: str | None) -> bool:
    return len((value or "").encode("utf-8")) >= _MIN_SECRET_BYTES


def _looks_like_placeholder_secret(value: str | None) -> bool:
    normalized = (value or "").strip().lower()
    return any(marker in normalized for marker in _PLACEHOLDER_SECRET_MARKERS)


def _is_local_url(value: str | None) -> bool:
    try:
        parsed = urlparse((value or "").strip())
    except Exception:
        return False
    return (parsed.hostname or "").lower() in _LOCAL_HOSTS


def _is_secure_public_url(value: str | None) -> bool:
    try:
        parsed = urlparse((value or "").strip())
    except Exception:
        return False
    return parsed.scheme.lower() in {"https", "wss"}


def _configured_public_urls(cfg: BaseConfig) -> list[tuple[str, str]]:
    keys = (
        "BACKEND_PUBLIC_BASE_URL",
        "FRONTEND_PUBLIC_BASE_URL",
        "GAME_WS_PUBLIC_BASE_URL",
        "CHAT_WS_PUBLIC_BASE_URL",
    )
    return [(key, str(getattr(cfg, key, "") or "").strip()) for key in keys]


def _has_game_server_credentials(raw: str | None) -> bool:
    if not (raw or "").strip():
        return False
    try:
        parsed = json.loads(raw or "")
    except Exception:
        return False
    if not isinstance(parsed, dict) or not parsed:
        return False
    for entry in parsed.values():
        if not isinstance(entry, dict):
            continue
        if str(entry.get("signing_secret") or "").strip():
            return True
    return False


def collect_startup_alerts(
    cfg: BaseConfig,
    *,
    app_role: StartupAppRole = "main_app",
) -> list[StartupAlert]:
    """Return startup safety alerts without logging or raising."""
    alerts: list[StartupAlert] = []
    is_production = _is_production(cfg)

    if is_production:
        if not _has_min_secret(getattr(cfg, "SECRET_KEY", "")):
            alerts.append(
                StartupAlert(
                    code="secret_key_missing_or_weak",
                    message="SECRET_KEY is missing or shorter than 32 bytes in production.",
                )
            )
        if not _has_min_secret(getattr(cfg, "JWT_SECRET_KEY", "")):
            alerts.append(
                StartupAlert(
                    code="jwt_secret_key_missing_or_weak",
                    message="JWT_SECRET_KEY is missing or shorter than 32 bytes in production.",
                )
            )
        if (getattr(cfg, "SECRET_KEY", "") or "") == (getattr(cfg, "JWT_SECRET_KEY", "") or ""):
            alerts.append(
                StartupAlert(
                    code="shared_secret_keys",
                    message="SECRET_KEY and JWT_SECRET_KEY are identical in production.",
                )
            )
        if _looks_like_placeholder_secret(getattr(cfg, "SECRET_KEY", "")):
            alerts.append(
                StartupAlert(
                    code="secret_key_placeholder",
                    message="SECRET_KEY appears to use a placeholder value in production.",
                )
            )
        if _looks_like_placeholder_secret(getattr(cfg, "JWT_SECRET_KEY", "")):
            alerts.append(
                StartupAlert(
                    code="jwt_secret_key_placeholder",
                    message="JWT_SECRET_KEY appears to use a placeholder value in production.",
                )
            )
        if not bool(getattr(cfg, "JWT_COOKIE_SECURE", True)):
            alerts.append(
                StartupAlert(
                    code="jwt_cookie_not_secure",
                    message="JWT_COOKIE_SECURE is disabled in production; auth cookies may be sent over HTTP.",
                )
            )

        origins = [str(origin).strip() for origin in (getattr(cfg, "CORS_ALLOWED_ORIGINS", []) or [])]
        if "*" in origins:
            alerts.append(
                StartupAlert(
                    code="cors_allows_wildcard",
                    message="CORS_ALLOWED_ORIGINS contains '*' while credentialed CORS is enabled.",
                )
            )
        local_origins = [origin for origin in origins if _is_local_url(origin)]
        if local_origins:
            alerts.append(
                StartupAlert(
                    code="cors_allows_localhost",
                    message="CORS_ALLOWED_ORIGINS includes localhost origins in production.",
                )
            )

        public_urls = _configured_public_urls(cfg)
        insecure_url_keys = [key for key, value in public_urls if value and not _is_secure_public_url(value)]
        if insecure_url_keys:
            alerts.append(
                StartupAlert(
                    code="public_urls_not_secure",
                    message=(
                        "Production public URL settings should use https or wss: "
                        + ", ".join(insecure_url_keys)
                        + "."
                    ),
                )
            )
        local_url_keys = [key for key, value in public_urls if value and _is_local_url(value)]
        if local_url_keys:
            alerts.append(
                StartupAlert(
                    code="public_urls_localhost",
                    message=(
                        "Production public URL settings still point at localhost: "
                        + ", ".join(local_url_keys)
                        + "."
                    ),
                )
            )

        if app_role == "main_app" and not _has_game_server_credentials(
            getattr(cfg, "GAME_SERVER_CREDENTIALS_JSON", "")
        ):
            alerts.append(
                StartupAlert(
                    code="game_server_credentials_missing",
                    message=(
                        "GAME_SERVER_CREDENTIALS_JSON is missing or invalid; "
                        "dedicated game servers cannot authenticate with the control plane."
                    ),
                )
            )

    if app_role == "game_server" and is_production:
        missing_identity_keys = [
            key
            for key in ("GAME_SERVER_SELF_ID", "GAME_SERVER_SELF_SIGNING_SECRET")
            if not str(getattr(cfg, key, "") or "").strip()
        ]
        if missing_identity_keys:
            alerts.append(
                StartupAlert(
                    code="game_server_identity_missing",
                    message=(
                        "Dedicated game server registry heartbeat is disabled; missing "
                        + ", ".join(missing_identity_keys)
                        + "."
                    ),
                )
            )

    return alerts


def emit_startup_alerts(
    app_role: StartupAppRole = "main_app",
    *,
    cfg: BaseConfig | None = None,
    logger: logging.Logger | None = None,
) -> list[StartupAlert]:
    """Log startup safety alerts and never prevent the application from booting."""
    startup_logger = logger or get_app_logger()
    try:
        alerts = collect_startup_alerts(cfg or get_app_config(), app_role=app_role)
    except Exception as exc:
        startup_logger.warning(
            f"[StartupAlert] startup_alerts_failed: Unable to evaluate startup safety alerts: {exc}"
        )
        return []

    for alert in alerts:
        startup_logger.warning(f"[StartupAlert] {alert.code}: {alert.message}")
    return alerts
